#include "bignum_samples.h"

/**
 * Values for this test can be generated by this python script
 *
```
import sys

def limbs32(value, bits):
    v = int(value) & ((1 << bits) - 1)   # two's-complement to `bits` bits
    mask = (1 << 32) - 1
    # little-endian 32-bit words: words[0] is least significant
    return [(v >> (32 * i)) & mask for i in range(bits // 32)]

if __name__ == "__main__":
    if len(sys.argv) < 4:
        sys.exit("usage: gen_limbs.py <signed|unsigned> <128|256|512> VALUE [VALUE ...]")
    bits = {"128": 128, "256": 256, "512": 512}[sys.argv[2]]
    for value in sys.argv[3:]:
        words = limbs32(value, bits)               # low word first
        lits = ", ".join(f"0x{w:08X}" for w in reversed(words))  # high word first
        print(f'{{"{value}", {{{lits}}}}},')
```
 *
 * Example:
 *     python convert.py signed 128 1 2 5
 *
 * Generates:
 *     {"1", {0x00000000, 0x00000000, 0x00000000, 0x00000001}},
 *     {"2", {0x00000000, 0x00000000, 0x00000000, 0x00000002}},
 *     {"5", {0x00000000, 0x00000000, 0x00000000, 0x00000005}},
 */

std::vector<TestSample> UnsignedInt128Samples() {
    return {
        /* ---- UNSIGNED: small / explicit-sign / leading-zero ---- */
        {"0", {0x00000000, 0x00000000, 0x00000000, 0x00000000}},
        {"1", {0x00000000, 0x00000000, 0x00000000, 0x00000001}},
        {"9", {0x00000000, 0x00000000, 0x00000000, 0x00000009}},
        {"10", {0x00000000, 0x00000000, 0x00000000, 0x0000000A}},
        {"42", {0x00000000, 0x00000000, 0x00000000, 0x0000002A}},
        {"12345", {0x00000000, 0x00000000, 0x00000000, 0x00003039}},
        {"00", {0x00000000, 0x00000000, 0x00000000, 0x00000000}},
        {"007", {0x00000000, 0x00000000, 0x00000000, 0x00000007}},

        /* ---- UNSIGNED: 2^32 limb boundary (val-1 / val / val+1) ---- */
        {"4294967295", {0x00000000, 0x00000000, 0x00000000, 0xFFFFFFFF}},
        {"4294967296", {0x00000000, 0x00000000, 0x00000001, 0x00000000}},
        {"4294967297", {0x00000000, 0x00000000, 0x00000001, 0x00000001}},

        /* ---- UNSIGNED: 2^64 limb boundary (val-1 / val / val+1) ---- */
        {"18446744073709551615", {0x00000000, 0x00000000, 0xFFFFFFFF, 0xFFFFFFFF}},
        {"18446744073709551616", {0x00000000, 0x00000001, 0x00000000, 0x00000000}},
        {"18446744073709551617", {0x00000000, 0x00000001, 0x00000000, 0x00000001}},

        /* ---- UNSIGNED: 2^96 limb boundary (val-1 / val / val+1) ---- */
        {"79228162514264337593543950335", {0x00000000, 0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF}},
        {"79228162514264337593543950336", {0x00000001, 0x00000000, 0x00000000, 0x00000000}},
        {"79228162514264337593543950337", {0x00000001, 0x00000000, 0x00000000, 0x00000001}},

        /* ---- UNSIGNED: powers of ten spanning the width ---- */
        {"100", {0x00000000, 0x00000000, 0x00000000, 0x00000064}},
        {"1000000000", {0x00000000, 0x00000000, 0x00000000, 0x3B9ACA00}},
        {"10000000000000000000", {0x00000000, 0x00000000, 0x8AC72304, 0x89E80000}},
        {"100000000000000000000000000000", {0x00000001, 0x431E0FAE, 0x6D7217CA, 0xA0000000}},
        {"100000000000000000000000000000000000000", {0x4B3B4CA8, 0x5A86C47A, 0x098A2240, 0x00000000}},

        /* ---- UNSIGNED: long all-9s in range, mixed-digit in range ---- */
        {"99999999999999999999999999999999999999", {0x4B3B4CA8, 0x5A86C47A, 0x098A223F, 0xFFFFFFFF}},
        {"123456789012345678901234567890123456789", {0x5CE0E9A5, 0x6015FEC5, 0xAADFA328, 0xAE398115}},

        /* ---- UNSIGNED: type maxima (constant + literals) ---- */
        {UINT128_MAX_STR, {0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF}},
        {"340282366920938463463374607431768211455", {0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF}},
        {"340282366920938463463374607431768211454", {0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFE}},

        /* ---- UNSIGNED: zero-padded in-range value (defends against a digit-COUNT
         *      overflow gate that counts leading zeros without stripping them).
         *      "0"+UINT_MAX is 40 chars but value == UINT_MAX, so it MUST convert;
         *      a count>39 gate would wrongly reject it as OVERFLOW. ---- */
        {"0340282366920938463463374607431768211455", {0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF}},
    };
}
